mapper.select:
SELECT COUPON_SN, COUPON_NM, DISC_TYPE, DISC_AMT, DISC_RATE, USE_LIMIT_CD, VALID_DAYS, USE_YN, REG_USER_ID, REG_DT, COUPON_CODE, COUPON_TYPE
FROM COUPON
WHERE COUPON_SN = #{couponSn}

mapper.update:
UPDATE COUPON
SET COUPON_NM = #{couponNm},
    DISC_AMT  = #{discAmt},
    USE_YN    = #{useYn}
WHERE COUPON_SN = #{couponSn}
  AND COUPON_TYPE = 'STUDY_POINT'
